"use client";

import React from 'react';
import Image from 'next/image';
import { motion } from 'framer-motion';
import { Mail, Phone, Calendar } from 'lucide-react';
import { GlassCard } from '../ui/GlassCard';

export const Appointment = () => {
  return (
    <section id="contacts" className="py-24 bg-white relative overflow-hidden">
      <div className="max-w-7xl mx-auto px-6 grid lg:grid-cols-2 gap-16 items-center">
        {/* Left Side: Decorative & Info */}
        <motion.div
          initial={{ opacity: 0, x: -30 }}
          whileInView={{ opacity: 1, x: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.8 }}
          className="space-y-12"
        >
          <div className="relative aspect-square w-full max-w-sm mx-auto lg:mx-0 rounded-[3rem] overflow-hidden shadow-2xl border-8 border-bone">
             <Image 
                src="https://images.unsplash.com/photo-1556228578-0d85b1a4d571?q=80&w=1974&auto=format&fit=crop" 
                alt="Clinic Interior" 
                fill 
                className="object-cover"
             />
          </div>

          <div className="space-y-6">
            <h2 className="text-4xl font-serif text-secondary">Make an Appointment</h2>
            <p className="text-secondary/60 max-w-md">
              Ready to begin your transformation? Schedule a private consultation with Dr. Badawy to discuss your personalized treatment plan.
            </p>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <ContactInfo icon={Phone} label="Call Us" value="+2-583-018-36-28" />
              <ContactInfo icon={Mail} label="Email Us" value="info@drbadawy.com" />
              <ContactInfo icon={Calendar} label="Hours" value="Mon-Sat: 09:00 - 18:00" />
            </div>
          </div>
        </motion.div>

        {/* Right Side: Simple Appointment Form Inspired by Screenshots */}
        <motion.div
           initial={{ opacity: 0, y: 30 }}
           whileInView={{ opacity: 1, y: 0 }}
           viewport={{ once: true }}
           transition={{ duration: 0.8 }}
        >
          <GlassCard className="p-10 border-none bg-bone/50 shadow-2xl">
            <form className="space-y-8">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                <FormInput label="Full Name" placeholder="Your name" />
                <FormInput label="Email Address" type="email" placeholder="email@example.com" />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                <FormInput label="Phone Number" type="tel" placeholder="+1..." />
                <div className="space-y-2">
                  <label className="text-[10px] uppercase font-bold tracking-widest text-secondary/40 ml-1">Preferred Procedure</label>
                  <select className="w-full bg-white border-b border-secondary/10 py-4 focus:outline-none focus:border-primary transition-colors text-secondary appearance-none">
                    <option>Select Procedure</option>
                    <option>Face Lifting</option>
                    <option>Breast Augmentation</option>
                    <option>Body Correction</option>
                    <option>Liposuction</option>
                  </select>
                </div>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] uppercase font-bold tracking-widest text-secondary/40 ml-1">Message (Optional)</label>
                <textarea 
                  rows={4}
                  placeholder="Tell us about your goals..."
                  className="w-full bg-white border-b border-secondary/10 py-4 focus:outline-none focus:border-primary transition-colors resize-none text-secondary"
                />
              </div>

              <button className="w-full bg-secondary text-white py-5 rounded-full font-bold uppercase tracking-[0.2em] text-sm hover:bg-secondary/90 transition-all shadow-xl shadow-secondary/20">
                Send Request
              </button>
            </form>
          </GlassCard>
        </motion.div>
      </div>
    </section>
  );
};

const ContactInfo = ({ icon: Icon, label, value }: { icon: any, label: string, value: string }) => (
  <div className="flex items-start space-x-4">
    <div className="p-3 bg-primary/10 rounded-2xl text-primary">
      <Icon className="w-5 h-5" />
    </div>
    <div>
      <p className="text-[10px] uppercase font-bold tracking-widest text-secondary/40">{label}</p>
      <p className="text-secondary font-serif">{value}</p>
    </div>
  </div>
);

const FormInput = ({ label, type = "text", placeholder }: { label: string, type?: string, placeholder: string }) => (
  <div className="space-y-2">
    <label className="text-[10px] uppercase font-bold tracking-widest text-secondary/40 ml-1">{label}</label>
    <input 
      type={type}
      placeholder={placeholder}
      className="w-full bg-white border-b border-secondary/10 py-4 focus:outline-none focus:border-primary transition-colors text-secondary placeholder:text-secondary/20"
    />
  </div>
);

"use client";

import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import { motion } from 'framer-motion';
import { ArrowRight } from 'lucide-react';
import api from '@/lib/api';
import { GlassCard } from '../ui/GlassCard';

interface Item {
  _id: string;
  title: string;
  description: string;
  imageUrl: string;
}

export const Services = () => {
  const [items, setItems] = useState<Item[]>([]);

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const { data } = await api.get('/items');
        setItems(data);
      } catch (err) {
        console.error('Failed to fetch services');
      }
    };
    fetchItems();
  }, []);

  return (
    <section id="services" className="py-32 bg-white relative overflow-hidden">
      <div className="max-w-7xl mx-auto px-6 relative z-10">
        <div className="text-center mb-20">
          <p className="font-script text-primary text-4xl mb-4 italic">your beauty</p>
          <h2 className="text-5xl font-serif text-secondary tracking-tight">
            Designed for people with real goals, <br />
            Our treatments help you feel like yourself.
          </h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {items.map((item, index) => (
            <motion.div
              key={item._id}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.8 }}
            >
              <div className="group cursor-pointer">
                <div className="relative aspect-[3/4] rounded-3xl overflow-hidden mb-6 shadow-xl group-hover:shadow-primary/10 transition-shadow">
                  <Image 
                    src={item.imageUrl} 
                    alt={item.title} 
                    fill 
                    className="object-cover group-hover:scale-110 transition-transform duration-1000"
                  />
                  <div className="absolute inset-0 bg-gradient-to-t from-secondary/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500 overflow-hidden" />
                  <div className="absolute bottom-6 left-6 right-6 translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-500">
                    <button className="w-full bg-white/20 backdrop-blur-md text-white py-3 rounded-xl border border-white/20 hover:bg-white/40 transition-colors flex items-center justify-center space-x-2">
                      <span>View Details</span>
                      <ArrowRight className="w-4 h-4" />
                    </button>
                  </div>
                </div>
                <h3 className="text-xl font-serif text-secondary mb-2 group-hover:text-primary transition-colors">{item.title}</h3>
                <div className="w-8 h-[2px] bg-primary group-hover:w-full transition-all duration-500" />
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

"use client";

import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import { motion } from 'framer-motion';
import { Quote } from 'lucide-react';
import api from '@/lib/api';

interface Comment {
  _id: string;
  username: string;
  description: string;
  profilePhoto: string;
}

export const Testimonials = () => {
  const [comments, setComments] = useState<Comment[]>([]);

  useEffect(() => {
    const fetchComments = async () => {
      try {
        const { data } = await api.get('/comments');
        setComments(data);
      } catch (err) {
        console.log(err)
        console.error('Failed to fetch testimonials');
      }
    };
    fetchComments();
  }, []);

  return (
    <section className="py-32 bg-secondary text-white relative overflow-hidden">
      <div className="absolute top-0 right-0 w-96 h-96 bg-primary/10 rounded-full blur-[120px]" />
      <div className="absolute bottom-0 left-0 w-96 h-96 bg-primary/10 rounded-full blur-[120px]" />

      <div className="max-w-7xl mx-auto px-6 relative z-10">
        <div className="text-center mb-20">
          <p className="font-script text-primary text-4xl mb-4 italic">gratitude</p>
          <h2 className="text-5xl font-serif tracking-tight">Voices of Transformation</h2>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {comments.map((comment, index) => (
            <motion.div
              key={comment._id}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1, duration: 0.8 }}
              className="bg-white/5 backdrop-blur-sm border border-white/10 p-8 rounded-[3rem] shadow-2xl flex flex-col justify-between"
            >
              <div>
                <Quote className="text-primary w-10 h-10 mb-6 opacity-40" />
                <p className="text-lg font-medium leading-relaxed italic text-white/80">
                  "{comment.description}"
                </p>
              </div>

              <div className="flex items-center space-x-4 mt-8 pt-8 border-t border-white/5">
                <div className="relative w-12 h-12 rounded-full overflow-hidden border border-primary/20">
                  <Image 
                    src={comment.profilePhoto || "https://api.dicebear.com/7.x/avataaars/svg?seed=fallback"} 
                    alt={comment.username} 
                    fill 
                    className="object-cover"
                  />
                </div>
                <div>
                  <h4 className="font-serif text-lg tracking-tight">{comment.username}</h4>
                  <p className="text-primary text-[10px] uppercase tracking-widest font-bold">Verified Patient</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};
